 func (m *DoltServerManager) checkDatabaseCount() {
 	databases, err := m.getDatabases()
 	if err != nil {
 		return // non-fatal
 	}

-	// Expected: one database per rig (hq, beads, gastown, wyvern, sky, beads_hop, etc.)
